parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"is_high_risk": {
			"type": "boolean",
			"description": "Whether the company is developing or deploying high-risk AI systems under the EU AI Act"
		},
		"risk_category": {
			"type": "string",
			"description": "The specific EU AI Act risk category if high-risk (e.g., biometric identification, law enforcement, critical infrastructure)"
		},
		"reasoning": {
			"type": "string",
			"description": "Explanation of why the company is or is not considered high-risk"
		},
		"confidence": {
			"type": "number",
			"description": "Confidence score from 0 to 1"
		}
	}
}

parameters.message:
=A high-risk AI Act warning email was successfully sent to {{ $json.company_name }}.

Risk Category: {{ $json.output.risk_category }}
Confidence: {{ $json.output.confidence }}
Reasoning: {{ $json.output.reasoning }}
